############################################################################ # Fix-KeywordFiles.ps1 # Fixes GitHub Pages frontmatter and metadata box formatting for keyword files # - Adds layout/title/parent/nav_order/permalink to frontmatter # - Wraps the ┌─...└─ metadata box in code fences # - Creates category index.md files if missing ############################################################################
$base = "C:\ASK\MyWorkspace\sk-keys\docs"
# ─── Category definitions ──────────────────────────────────────────────────── $categories = @( @{ Dir = "Java"; Parent = "Java Fundamentals"; PermalinkBase = "/java/"; Nums = 51..65 } @{ Dir = "Testing"; Parent = "Testing"; PermalinkBase = "/testing/"; Nums = 412..423 } @{ Dir = "Clean Code"; Parent = "Clean Code"; PermalinkBase = "/clean-code/"; Nums = 424..433 } @{ Dir = "DevOps & SDLC"; Parent = "DevOps & SDLC"; PermalinkBase = "/devops-sdlc/"; Nums = 450..460 } )
# Category index.md definitions $catIndexes = @( @{ Dir = "Testing" Title = "Testing" Parent = "Documentation" NavOrder = 13 Permalink = "/testing/" Description = "Testing strategies, methodologies, and tools — Unit, Integration, TDD, BDD, Mutation Testing." Range = "412–423" Count = 12 } @{ Dir = "Clean Code" Title = "Clean Code" Parent = "Documentation" NavOrder = 14 Permalink = "/clean-code/" Description = "Clean code principles — Cohesion, Coupling, Abstraction, Refactoring, Technical Debt." Range = "424–433" Count = 10 } @{ Dir = "DevOps & SDLC" Title = "DevOps & SDLC" Parent = "Documentation" NavOrder = 15 Permalink = "/devops-sdlc/" Description = "DevOps practices and SDLC — CI/CD, Blue-Green, GitOps, SRE, Error Budget, IaC." Range = "450–460" Count = 11 } )
# ─── Helper: generate URL slug ─────────────────────────────────────────────── function Slugify([string]$name) { $s = $name.ToLower() $s = $s -replace '[^a-z0-9\s\-]', '' $s = $s -replace '\s+', '-' $s = $s -replace '-+', '-' $s.Trim('-') }
# ─── Helper: fix a single keyword file ────────────────────────────────────── function Fix-KeywordFile([string]$filePath, [string]$parent, [string]$permalinkBase, [int[]]$nums) { $enc = [System.Text.Encoding]::UTF8 $raw = [System.IO.File]::ReadAllText($filePath, $enc) $content = $raw $modified = $false $fileName = Split-Path $filePath -Leaf
# --- Check number is in range $numMatch = [regex]::Match($fileName, '^\d+') if (-not $numMatch.Success) { return } $num = [int]$numMatch.Value if ($nums -and $num -notin $nums) { return }
# --- Extract title from # NNN — Title heading $headMatch = [regex]::Match($content, '#\s*\d+\s*[—\-]+\s*(.+?)[\r\n]') $title = if ($headMatch.Success) { $headMatch.Groups[1].Value.Trim() } else { $fileName -replace '^\d+ — ', '' -replace '\.md$', '' } $slug = Slugify $title $permalink = "$permalinkBase$slug/"
# --- 1. Fix frontmatter: add GitHub Pages fields if missing # Split on the first two --- markers $fmEnd = $content.IndexOf('---', 3) # find closing --- if ($fmEnd -gt 0 -and $content -notmatch 'layout:\s') { $newFields = "layout: default`r`ntitle: `"$title`"`r`nparent: `"$parent`"`r`nnav_order: $num`r`npermalink: $permalink`r`n" # Insert new fields right after the opening ---\n $afterOpen = $content.IndexOf("`n", 0) + 1 # position after first "---\n" $content = $content.Substring(0, $afterOpen) + $newFields + $content.Substring($afterOpen) $modified = $true }
# --- 2. Fix metadata box: wrap ┌─...└─ in code fences if not already $boxStart = $content.IndexOf("┌─") if ($boxStart -ge 0) { # Check if already inside a code block (look backwards for ```) $lookBack = [Math]::Max(0, $boxStart - 20) $before = $content.Substring($lookBack, $boxStart - $lookBack) if ($before -notmatch '```\s*$') { $boxEnd = $content.IndexOf("└─", $boxStart) if ($boxEnd -ge 0) { $boxLineEnd = $content.IndexOf("`n", $boxEnd) if ($boxLineEnd -eq -1) { $boxLineEnd = $content.Length } else { $boxLineEnd++ }
$boxText = $content.Substring($boxStart, $boxLineEnd - $boxStart) $fenced = "``````" + "`r`n" + $boxText + "``````" + "`r`n" $content = $content.Substring(0, $boxStart) + $fenced + $content.Substring($boxLineEnd) $modified = $true } } }
if ($modified) { [System.IO.File]::WriteAllText($filePath, $content, $enc) Write-Host " ✅ Fixed: $fileName" -ForegroundColor Green } else { Write-Host " ⏭ OK: $fileName" -ForegroundColor DarkGray } }
# ─── Helper: create category index.md ──────────────────────────────────────── function Create-CategoryIndex([hashtable]$ci) { $dir = Join-Path $base $ci.Dir $indexPath = Join-Path $dir "index.md"
if (Test-Path $indexPath) { $existing = Get-Content $indexPath -Raw if ($existing -match 'has_children:') { Write-Host " ⏭ index.md already OK: $($ci.Dir)" -ForegroundColor DarkGray return } }
$indexContent = @" --- layout: default title: "$($ci.Title)" parent: "$($ci.Parent)" nav_order: $($ci.NavOrder) has_children: true permalink: $($ci.Permalink) ---
# $($ci.Title)
$($ci.Description)
**Keywords:** $($ci.Range) ($($ci.Count) terms)
---
| # | Keyword | |-----|---------| "@
Set-Content $indexPath $indexContent -Encoding UTF8 Write-Host " ✅ Created index.md: $($ci.Dir)" -ForegroundColor Cyan }
# ───────────────────────────────────────────────────────────────────────────── # MAIN # ─────────────────────────────────────────────────────────────────────────────
Write-Host "" Write-Host "═══ Step 1: Create missing category index.md files ═══" -ForegroundColor Yellow foreach ($ci in $catIndexes) { $dirPath = Join-Path $base $ci.Dir if (-not (Test-Path $dirPath)) { New-Item -ItemType Directory -Path $dirPath -Force | Out-Null Write-Host " Created dir: $($ci.Dir)" -ForegroundColor Cyan } Create-CategoryIndex $ci }
Write-Host "" Write-Host "═══ Step 2: Fix keyword file frontmatter + metadata box ═══" -ForegroundColor Yellow foreach ($cat in $categories) { $dirPath = Join-Path $base $cat.Dir Write-Host "" Write-Host " [$($cat.Dir)]" -ForegroundColor Magenta if (-not (Test-Path $dirPath)) { Write-Host " ⚠ Directory not found: $dirPath" -ForegroundColor Red continue }
$files = Get-ChildItem $dirPath -Filter "*.md" | Where-Object { $_.Name -ne "index.md" } | Sort-Object Name foreach ($file in $files) { Fix-KeywordFile $file.FullName $cat.Parent $cat.PermalinkBase $cat.Nums } }
Write-Host "" Write-Host "═══ Done! ═══" -ForegroundColor Green

